from dataclasses import dataclass, field
from typing import Any


@dataclass
class Event:
    event_type: str
    payload: dict[str, Any]


@dataclass
class Result:
    success: bool
    changes: list[str] = field(default_factory=list)


def process_event(event: Event, dry_run: bool = False) -> Result:
    """Process an event, optionally in dry-run mode."""
    if dry_run:
        return Result(success=True, changes=[])
    return Result(success=True, changes=["updated"])


def batch_process(events: list[Event]) -> list[Result]:
    return [process_event(e) for e in events]

