from src.processor import Event, process_event


def handle_incoming(raw_data: dict) -> None:
    event = Event(event_type=raw_data["type"], payload=raw_data)
    result = process_event(event)
    if not result.success:
        raise RuntimeError(f"Processing failed for {raw_data['type']}")
